/**
 * Returns the chronological action history for a single lead in the
leads-hub workflow. Each entry corresponds to a `call_attempts` row
for the lead, joined with the acting CSR's display name. Entries
may carry follow-up state pulled from the parent lead row
(`spokeResult`, `callbackAt`, `appointmentDate`, `appointmentTime`)
when the action drove a callback or appointment booking; otherwise
those fields are null.

 * @summary Get the action history (call attempts, texts, voicemails) for a lead
 */
export const GetLeadHistoryParams = zod.object({
  leadId: zod.coerce.number(),
});

export const GetLeadHistoryResponse = zod.object({
  history: zod.array(
    zod
      .object({
        id: zod.number(),
        leadId: zod.number(),
        userId: zod.number(),
        method: zod
          .string()
          .describe(
            "Channel the action was performed on (`call`, `text`,\n`voicemail`, `voicemail_drop`, `transfer`, â€¦). Mirrors the\npersisted `call_attempts.method` column.\n",
          ),
        outcome: zod
          .string()
          .describe(
            "Coarse-grained outcome of the action (e.g. `answered`,\n`no_answer`, `appt_confirmed`, `transferred`).\n",
          ),
        platform: zod
          .string()
          .nullish()
          .describe(
            "Platform the action was logged from (`native`, `podium`, â€¦).\n",
          ),
        attemptedAt: zod.date(),
        notes: zod.string().nullish(),
        actionType: zod
          .string()
          .nullish()
          .describe(
            "Refined action verb chosen by the operator (`call`, `text`,\n`voicemail_drop`, `transfer`). Distinct from `method` so the\nUI can re-render legacy rows that only set `method`.\n",
          ),
        callResult: zod.string().nullish(),
        vmResult: zod.string().nullish(),
        textResult: zod.string().nullish(),
        deadReason: zod.string().nullish(),
        csrName: zod
          .string()
          .describe("Display name of the CSR who logged the action."),
        spokeResult: zod
          .string()
          .nullish()
          .describe(
            "When the action was a `spoke_with_customer` call (or a\ntext\/voicemail equivalent), captures the sub-outcome the\noperator selected (`call_back`, `appointment_set`, `dead`).\nPersisted on `call_attempts.spoke_result` so the editor can\npre-fill it when reopening the action. Null on actions that\ndid not branch on a spoke result.\n",
          ),
        callbackAt: zod
          .date()
          .nullish()
          .describe(
            "Scheduled callback timestamp when the action's spoke result\nwas `call_back`. Persisted on `call_attempts.callback_at`\n(the lead row's `callback_at` is also updated, but the\nper-attempt copy is what the editor reads back).\n",
          ),
        appointmentDate: zod
          .string()
          .nullish()
          .describe(
            "ISO date (YYYY-MM-DD) of the appointment booked by this\naction. Persisted on `call_attempts.appointment_date`. Null\non actions that did not book an appointment.\n",
          ),
        appointmentTime: zod
          .string()
          .nullish()
          .describe(
            "Local time-of-day (HH:mm) of the appointment booked by this\naction. Persisted on `call_attempts.appointment_time`. Null\non actions that did not book an appointment.\n",
          ),
      })
      .describe(
        "A single action recorded against a lead in the leads-hub workflow.\nSourced from the `call_attempts` table (joined with the acting CSR's\ndisplay name). Follow-up fields like `spokeResult`, `callbackAt`,\n`appointmentDate`, and `appointmentTime` are persisted directly on\nthe call attempt row so re-opening a past attempt for editing\npre-fills the originally-chosen values. For legacy attempts written\nbefore these columns existed, the server falls back to attributing\nthe parent lead row's mirror to the most recent\n`spoke_with_customer` attempt; everything else is null.\n",
      ),
  ),
});

